//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "settings.xml settings (updateFields, decimalSymbol, compat) and
//! Mail Merge / ODSO".
//!
//! Each `#[test]` encodes a Word-consumption / serializer-emission constraint
//! mined from ECMA-376 / ISO 29500-1 and the [MS-*] implementer notes. A
//! FAILING assertion here is NOT a flaky test to be silenced: it encodes a real
//! Word-compliance gap in the stemma engine (stemma diverges from what Word
//! does). Fix the engine (or, if the test encodes the wrong expectation, fix the
//! test from the domain rule) — never weaken an assertion to make it pass.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim. `reserialize()` of an unedited document therefore reflects
//! stemma's verbatim-preservation contract, not Word's render-time
//! normalization. `xmlContains`/`xmlOmits` assertions below are only used for
//! markup stemma actively generates/restructures or preserves verbatim (field
//! codes, element ordering, structural synthesis, opens-clean). Word *consumption*
//! semantics are asserted on the read side (`read_accepted`/`read_rejected`).

use std::io::Read;

use stemma::api::Document;

// ─── Prelude: minimal .docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (already including any `<w:sectPr/>`). `extra_parts`
/// is a list of `(part_path, xml)` pairs (e.g. `("word/styles.xml", "…")`);
/// each gets a Content_Types override and is written into the zip.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-Types: defaults + document override + one override per extra part.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = content_type_for(part);
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;

    // word/_rels/document.xml.rels: relate any extra parts that need it.
    let mut doc_rel_entries = String::new();
    let mut next_rid = 100;
    for (part, _) in extra_parts {
        if let Some((rel_type, target)) = doc_rel_for(part) {
            doc_rel_entries.push_str(&format!(
                r#"<Relationship Id="rIdX{next_rid}" Type="{rel_type}" Target="{target}"/>"#
            ));
            next_rid += 1;
        }
    }
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

fn content_type_for(part: &str) -> &'static str {
    match part {
        "word/styles.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        }
        "word/numbering.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        }
        "word/settings.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.settings+xml"
        }
        other => panic!("make_docx: no content-type mapping for extra part {other}"),
    }
}

fn doc_rel_for(part: &str) -> Option<(&'static str, &'static str)> {
    match part {
        "word/styles.xml" => Some((
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
            "styles.xml",
        )),
        "word/numbering.xml" => Some((
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
            "numbering.xml",
        )),
        "word/settings.xml" => Some((
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/settings",
            "settings.xml",
        )),
        _ => None,
    }
}

/// Unzip a `.docx` and return the contents of `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse → serialize (default ExportOptions) → return the re-serialized
/// `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// Assert that `haystack` contains each `needle` in order (substitute for a
/// regex with ordered `.*` separators). Returns true iff all are present in the
/// given sequence.
fn contains_in_order(haystack: &str, needles: &[&str]) -> bool {
    let mut pos = 0;
    for needle in needles {
        match haystack[pos..].find(needle) {
            Some(off) => pos += off + needle.len(),
            None => return false,
        }
    }
    true
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

fn opens_clean(bytes: &[u8]) -> stemma::ValidationReport {
    stemma::api::validate(bytes)
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[test]
fn mergefield_empty_cached_result_reads_empty() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Name: </w:t></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> MERGEFIELD MiddleName </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r><w:r><w:t xml:space="preserve"> end</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Name:  end",
        "ISO 29500-1 §17.16.18/§17.16.23/§17.16.2 — empty result region (separate immediately \
         followed by end) contributes no text; only 'Name: ' and ' end' are document text and the \
         MERGEFIELD instruction stays hidden"
    );
    assert_eq!(
        reject_text(&b),
        "Name:  end",
        "ISO 29500-1 §17.16.18/§17.16.23/§17.16.2 — no tracked changes; rejected view equals \
         accepted view (empty field result, code hidden)"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.18 — begin/separate/end with an empty result region is a well-formed \
         complex field; Word opens it without repair. Issues: {:?}",
        r.issues
    );
}

#[test]
fn mergefield_multirun_cached_result_concatenated_in_read() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> MERGEFIELD FullName </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:rPr><w:b/></w:rPr><w:t xml:space="preserve">Ada </w:t></w:r><w:r><w:t>Lovelace</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "Ada Lovelace",
        "ISO 29500-1 §17.16.2/§17.16.18/§17.16.23 — every run between separate and end is document \
         text; the two cached result runs concatenate to 'Ada Lovelace' and the instruction is \
         hidden"
    );
    assert_eq!(
        reject_text(&b),
        "Ada Lovelace",
        "ISO 29500-1 §17.16.2/§17.16.18/§17.16.23 — no tracked changes; rejected read equals \
         accepted read (full concatenated result, code hidden)"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.18 — a complex field with multiple formatted result runs is valid run \
         content; Word opens it without repair. Issues: {:?}",
        r.issues
    );
}

#[test]
fn mergefield_general_format_switch_preserved_and_hidden() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> MERGEFIELD City \* Upper \* MERGEFORMAT </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>LONDON</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"MERGEFIELD City \* Upper \* MERGEFORMAT"#),
        "ISO 29500-1 §17.16.5.35/§17.16.18/§17.16.23 — general-format switches are part of the \
         field instruction; stemma round-trips field code byte-verbatim, so the full instruction \
         must survive. Got:\n{xml}"
    );
    assert_eq!(
        accept_text(&b),
        "LONDON",
        "ISO 29500-1 §17.16.18/§17.16.23 — only the result region between separate and end is \
         document text; the \\* switches must not leak into the read view"
    );
    assert_eq!(
        reject_text(&b),
        "LONDON",
        "ISO 29500-1 §17.16.18/§17.16.23 — no tracked changes; rejected view equals accepted view \
         (cached result visible, switches hidden)"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.18 — a complex MERGEFIELD with \\* switches in instrText is valid run \
         content; Word opens it without repair. Issues: {:?}",
        r.issues
    );
}

#[test]
fn fldsimple_mergefield_with_switch_instr_preserved() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Hi </w:t></w:r><w:fldSimple w:instr=" MERGEFIELD FirstName \* Upper "><w:r><w:t>ADA</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:fldSimple"),
        "ISO 29500-1 §17.16.2/§17.16.19 — the simple field shall be represented by the fldSimple \
         element; the re-serialized document must keep it, not flatten to plain text. Got:\n{xml}"
    );
    assert!(
        xml.contains(r#"MERGEFIELD FirstName \* Upper"#),
        "ISO 29500-1 §17.16.5.35 — the instr attribute carries the full field instruction \
         including the \\* Upper switch; it must survive re-serialization unchanged. Got:\n{xml}"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.19 — fldSimple with required instr (including a switch) and a result \
         run is valid CT_SimpleField content; Word opens it without repair. Issues: {:?}",
        r.issues
    );
}

#[test]
fn mergeformat_switch_complex_field_preserved_and_not_read() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> TIME \@ "HH:mm:ss" \* MERGEFORMAT </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>17:02:</w:t></w:r><w:r><w:rPr><w:u w:val="single"/></w:rPr><w:t>32</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"\* MERGEFORMAT"#),
        "ISO 29500-1 §17.16.4.3 — the general-formatting-switch is part of the field code and must \
         be preserved verbatim on serialize, not stripped. Got:\n{xml}"
    );
    assert!(
        xml.contains(r#"\@ "HH:mm:ss""#),
        "ISO 29500-1 §17.16.4.1 — the date-and-time picture switch is part of the instruction and \
         is preserved verbatim. Got:\n{xml}"
    );
    assert!(
        contains_in_order(
            &xml,
            &[
                r#"fldCharType="begin""#,
                "instrText",
                r#"fldCharType="separate""#,
                r#"fldCharType="end""#,
            ],
        ),
        "ISO 29500-1 §17.16.1 — a complex field must keep begin<instrText<separate<result<end \
         ordering; structure must not be reordered or corrupted. Got:\n{xml}"
    );
    assert_eq!(
        accept_text(&b),
        "17:02:32",
        "ISO 29500-1 §17.16.4.3/§17.16.1 — only the runs between separate and end are document \
         text; the instruction (incl. switches) is never read; the two result runs concatenate"
    );
    assert_eq!(
        reject_text(&b),
        "17:02:32",
        "ISO 29500-1 §17.16.1 — no tracked change present, so accept and reject views are identical"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.1 — a well-formed complex field with switches is valid OOXML; Word \
         opens it without repair. Issues: {:?}",
        r.issues
    );
}

#[test]
fn mergefield_quoted_name_with_m_switch_verbatim() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Dear </w:t></w:r><w:r><w:fldChar w:fldCharType="begin"/></w:r><w:r><w:instrText xml:space="preserve"> MERGEFIELD "Last Name" \m </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>Doe</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"MERGEFIELD "Last Name" \m"#),
        "ISO 29500-1 §17.16.1/§17.16.5.35 — the quoted multi-word argument and the \\m switch are \
         part of the field code and must serialize verbatim. Got:\n{xml}"
    );
    assert_eq!(
        accept_text(&b),
        "Dear Doe",
        "ISO 29500-1 §17.14.36 — only the cached result run ('Doe') between separate and end is \
         document text; the MERGEFIELD instruction is never read"
    );
    assert_eq!(
        reject_text(&b),
        "Dear Doe",
        "ISO 29500-1 §17.14.36 — no tracked change present, so accept and reject views match"
    );
    assert!(
        !xml.contains("<w:t>MERGEFIELD"),
        "ISO 29500-1 §17.14 — the instruction must stay inside instrText, never be flattened into \
         a displayable w:t run. Got:\n{xml}"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.16.1 — a well-formed complex MERGEFIELD with a quoted argument is valid \
         OOXML; Word opens it without repair. Issues: {:?}",
        r.issues
    );
}

