#[test]
fn complex_mergefield_with_flddata_blob_preserved() {
    let body = r#"<w:p><w:r><w:fldChar w:fldCharType="begin"><w:fldData xml:space="preserve">UEsDBBQA</w:fldData></w:fldChar></w:r><w:r><w:instrText xml:space="preserve"> MERGEFIELD Company </w:instrText></w:r><w:r><w:fldChar w:fldCharType="separate"/></w:r><w:r><w:t>«Company»</w:t></w:r><w:r><w:fldChar w:fldCharType="end"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "«Company»",
        "ISO 29500-1 §17.14.20/§17.16.18 — with no tracked change, only the result run between \
         separate and end is document text; the instrText code and the fldData blob must never \
         leak into read text"
    );
    assert_eq!(
        reject_text(&b),
        "«Company»",
        "ISO 29500-1 §17.14.20/§17.16.18 — accept==reject for an untracked field; the readable \
         body is the cached result run, never the fldData cache"
    );
    let r = opens_clean(&b);
    assert!(
        r.ok,
        "ISO 29500-1 §17.14.20 / Annex A CT_FldChar — fldData on a begin fldChar is schema-valid \
         (CT_FldChar/CT_Text), so the package opens without repair. Issues: {:?}",
        r.issues
    );
}
